package evaluation

import "fmt"

// EvaluationError wraps a storage error with evaluation context, including
// the namespace key, flag key, and evaluation phase that failed.
type EvaluationError struct {
	NamespaceKey string
	FlagKey      string
	Phase        string
	inner        error
}

// newEvaluationError constructs an EvaluationError wrapping the given error
// with the supplied evaluation context.
func newEvaluationError(namespaceKey, flagKey, phase string, err error) *EvaluationError {
	return &EvaluationError{
		NamespaceKey: namespaceKey,
		FlagKey:      flagKey,
		Phase:        phase,
		inner:        err,
	}
}

// Error implements the error interface. It returns a descriptive message that
// includes the evaluation phase, namespace, flag key, and the underlying error.
func (e *EvaluationError) Error() string {
	return fmt.Sprintf("evaluating %s for namespace %q flag %q: %s", e.Phase, e.NamespaceKey, e.FlagKey, e.inner.Error())
}

// Unwrap returns the underlying error, enabling errors.Is and errors.As to
// traverse the error chain.
func (e *EvaluationError) Unwrap() error {
	return e.inner
}

